+/** Run a side effect when a task resolves, preserving its value and rejection. */
+export function tap<T, E>(task: Task<T, E>, fn: (value: T) => void): Task<T, E>;
+export function tap<T, E>(fn: (value: T) => void): (task: Task<T, E>) => Task<T, E>;
+export function tap<T, E>(
+  taskOrFn: Task<T, E> | ((value: T) => void),
+  maybeFn?: (value: T) => void
+): Task<T, E> | ((task: Task<T, E>) => Task<T, E>) {
+  if (maybeFn === undefined) return (task) => tap(task, taskOrFn as (value: T) => void);
+  return (taskOrFn as Task<T, E>).inspect(maybeFn);
+}
+
+/** Run a side effect when a task rejects, preserving its value and rejection. */
+export function tapRejected<T, E>(task: Task<T, E>, fn: (error: E) => void): Task<T, E>;
+export function tapRejected<T, E>(fn: (error: E) => void): (task: Task<T, E>) => Task<T, E>;
+export function tapRejected<T, E>(
+  taskOrFn: Task<T, E> | ((error: E) => void),
+  maybeFn?: (error: E) => void
+): Task<T, E> | ((task: Task<T, E>) => Task<T, E>) {
+  if (maybeFn === undefined) return (task) => tapRejected(task, taskOrFn as (error: E) => void);
+  return (taskOrFn as Task<T, E>).inspectRejected(maybeFn);
+}
+
+/** Retry a task-producing function up to `n` additional times after rejection. */
+export function retryN<T, E>(n: number, fn: () => Task<T, E>): Task<T, E> {
+  const attempt = (remaining: number): Task<T, E> =>
+    fn().orElse((error) => (remaining > 0 ? attempt(remaining - 1) : Task.reject<T, E>(error)));
+  return attempt(Math.max(0, Math.floor(n)));
+}
